35 struct TextCacheKey{ // Store mesh of common reused texts, so we dont recreate them each frame, if the text changes.
36     std::string text;
37     Color color;
38 
39     bool operator<(const TextCacheKey& other) const {
40         if(text != other.text) return text < other.text;
41         return color.toRGBA32() < other.color.toRGBA32();
42     }
43 };
44 
46 struct FontCharacter{
47     float u0, v0, u1, v1;
48     float sizeX, sizeY;
49     float bearingX, bearingY;
50     float advance;
51 };
52 
54 class Font{
55     protected:
56         PAsset assetPtr;
57         PTexture textureAtlasPtr;
58         PMaterial materialCachePtr;
59         float fontSize;
60 
61         std::array<FontCharacter, 128> characters;
62         std::map<TextCacheKey, std::shared_ptr<ModelPart>> meshCache;
63 
67         virtual void _initFont() = 0;
68     public:
69 
70         inline static Logbot FontLogger = Logbot::CreateInstance("Font");
71 
75         Font() : fontSize(0) {};
76         virtual ~Font() = default;
77 
78 
79         virtual void drawText(std::string text = "", Math3D::Vec2 position = Math3D::Vec2(0,0), PCamera camera = nullptr, Color color = Color::WHITE, bool useCache = true) = 0;
80         virtual bool supportsQueuedDrawing() const { return false; }
81         virtual void beginFrame(PCamera camera) {}
82         virtual void flushQueuedText(PCamera camera) {}
83         void clearCache(){
84             this->meshCache.clear();
85         }
86 
87         // The goal is to have multiple font engines for specific loading,
88         // so i could do auto font = Font::Create<FreeTypeFont>(assetPtr, 24.0f)
89         template<typename T>
90         static inline std::shared_ptr<T> Create(PAsset asset, float fontSize = 18.0f){
91             static_assert(std::is_base_of<Font, T>::value, "Class must inherit from Font.");
92 
93             if(!asset){
94                 FontLogger.Log(LOG_ERRO, "Asset was null");
95                 return nullptr;
96             }
97 
98             if(!asset->loaded()){
99                 FontLogger.Log(LOG_ERRO, "Cannot create font from unloaded asset, make sure its loaded, call Asset::load() or AssetManager::getOrLoad()");
100                 return nullptr;
101             }
102 
103             auto font = std::make_shared<T>();
104             font->assetPtr = asset;
105             font->fontSize = fontSize;
106             font->_initFont();
107     
108             return font;
109         }
110 
111         PAsset getAssetPointer(){
112             return this->assetPtr;
113         }
114 }; 
115 
116 typedef std::shared_ptr<Font> PFont;
